import java.io.*; // for Input/Output streams and their respective classes like BufferedReader etc...
  
public class java_52908_SocketServer_A01 {    
    public static void main(String args[]) throws Exception 
    {     
        ServerSocket server = new ServerSocket(6013);      
        
	// Create a thread for each client request. The 'new ClientHandlerThread' will handle the specific connection from one of our clients (web browsers). When you run your program, it listens on port 6012 and waits to accept incoming connections...   if yes then when another user connects through this socket..
        while(true) {    	      	   		   			     									 // This is a blocking call that will wait until new client comes. It means server's thread keeps running even after main function execution ends till the condition inside loop becomes false, here it never gets true so infinite waiting and therefore does not stop our socket service at all due to while(true) statement in if block..
            Socket sock = server.accept();    	      	   		   			     									 // Accepts incoming connection from a client 	 
               System.out.println("Client connected");  	     	       							// If there is no exception at this line, then new thread will create for handling the request of that specific socket coming to server...             if yes and so on..          			    		   	      	   									 // And finally when it ends up with true inside loop condition 
               Thread t = new ClientHandlerThread(sock);       	       	// Creating a client handler thread   for each connection, So that multiple clients can connect to the server.         if yes then at any given point in time all threads will be running on this single socket (server)...      	   	     // Newly created Thread takes care of specific request from one particular connected sock
               t.start(); 	       	 			     									   			// Starts thread execution here, When we run our program then it creates a new client handler for each time when someone tries to connect through this socket...   if yes and so on..	      	    // Then at the end of that infinite waiting loop after creating all threads until server's main function ends which will stop accepting connections from any clients or thread.
        }   		 	 			     									    	// So, basically when user connect to our program then it creates a separate socket for each connection and starts handling requests on this particular specific sockets (server) using different threads...   if yes..then at the end of that infinite waiting loop after creating all thread until server's main function ends which will stop accepting connections from any clients or new users.
    }      // End while(true).  When true becomes false, our program stops running due to this condition in case when user tries connection through socket and it fails at ClientHandlerThread creation inside the loop as well because of exception handling... if yes then ServerSocket part will not accept any more client connections which makes server stop working.
}   // End main method ends here  So, When true becomes false due to this condition in case when user tries connection through socket and it fails at accepting new clients or thread creation inside the loop as well because of exception handling... then ServerSocket part will not accept any more client connections which makes server stop working.